import os
import boto3
from pathlib import Path
import joblib
import logging

def load_latest_model():
    model_path = os.environ.get('MODEL_PATH')
    if not model_path:
        raise ValueError("MODEL_PATH environment variable not set")
    
    if model_path.startswith('s3://'):
        return load_from_s3(model_path)
    else:
        return load_from_local(model_path)

def load_from_s3(s3_path):
    s3 = boto3.client('s3')
    bucket, key = s3_path[5:].split('/', 1)
    
    # Get all objects with the prefix
    paginator = s3.get_paginator('list_objects_v2')
    pages = paginator.paginate(Bucket=bucket, Prefix=key)
    
    latest_version = None
    latest_modified = None
    
    for page in pages:
        if 'Contents' not in page:
            continue
        for obj in page['Contents']:
            if latest_modified is None or obj['LastModified'] > latest_modified:
                latest_modified = obj['LastModified']
                latest_version = obj['Key']
    
    if latest_version is None:
        raise FileNotFoundError("No model version found in S3")
    
    # Download the latest model
    model_key = latest_version
    model_path = f"/tmp/{Path(model_key).name}"
    
    s3.download_file(bucket, model_key, model_path)
    return joblib.load(model_path)

def load_from_local(local_path):
    path = Path(local_path)
    if path.is_dir():
        # Find latest modified file
        latest_file = max(path.iterdir(), key=lambda f: f.stat().st_mtime)
        return joblib.load(latest_file)
    else:
        return joblib.load(path)

# Load model on startup
try:
    model = load_latest_model()
    logging.info("Model loaded successfully")
except Exception as e:
    logging.error(f"Failed to load model: {e}")
    raise

